var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"예, 이제 곧 유물보관소로 진입할 예정입니다.","JPN":"はい、間もなく遺物保管所に進入予定です。","ENG":"Yes, we're about to enter the artifact storage.","TWN":"好，接下來要進入遺物保管所。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"게이트를 열어주시기 바랍니다.","JPN":"ゲートを開けてください。","ENG":"Please open the gate.","TWN":"請開門。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"걱정 마시죠. 늘 그래왔듯 안전은 확실히 확보해두고 있습니다.","JPN":"ご安心を。いつもどおり、安全確保には万全を期しています。","ENG":"Don't worry. Everything's secure, as usual.","TWN":"請放心，安全是一如既往地有保障的。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"네?","JPN":"ん？","ENG":"Pardon?","TWN":"什麼？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"이 외딴 황무지에 차원도약좌표가 열리다니요, 그게 무슨......","JPN":"こんな人里離れた荒地に次元跳躍の座標が\\n開くなんて、まさかそんな……","ENG":"Someone's making a dimension jump here, in the middle of this wilderness? That's—","TWN":"這樣的荒地竟然會開啟次元跳躍座標，這到底……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"우와악! 위험해!","JPN":"うわぁ！　あぶない！","ENG":"Waaaah! Watch out!","TWN":"嗚哇！危險！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"뭐, 뭐지? 도로 위로 갑자기 함선이 나타나다니!","JPN":"な、何だ？　道路上にいきなり艦船が現れたぞ！","ENG":"W-what's that? A ship showed up in the middle of the road all of a sudden!","TWN":"什、什麼？道路上突然出現了艦船！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"......뭐야, 저 함선은? 다이브 좌표 계산을 잘못한 건가?","JPN":"……なんだあの艦船は？　ダイブ座標の計算を\\n間違えたのか？","ENG":"What's wrong with that ship? Did it miscalculate its Dive coordinates?","TWN":"……這艦船是怎麼回事？是算錯了躍入座標嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"그런 것 치곤 보란 듯이 길을 가로막고 있는데요?","JPN":"それにしてはこれ見よがしに道を塞いでいますが……","ENG":"But it looks like it's here on purpose, to block the road or something.","TWN":"但它看起來並不慌張啊？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"전 대원에게 알린다! 선두 차량이 미확인 함선에 의해 진로를 차단당했다.","JPN":"全隊員に告ぐ！　未確認の艦船によって先頭車両の進路を塞がれた。","ENG":"Attention, everyone! Our lead car has been stopped by an unidentified ship.","TWN":"全隊員請注意！領頭車前方被不明艦船擋住了去路。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"전투에 대비해 전원 신속히 선두와 거리를 좁혀라.","JPN":"戦闘に備えて、全員速やかに先頭との距離を縮めるように。","ENG":"Everyone, get close to the lead car and be ready for combat.","TWN":"全員準備戰鬥，縮小與領頭車輛的距離。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"......호송대 규모는?","JPN":"……搬送部隊の規模は？","ENG":"The size of the convoy?","TWN":"……護送隊規模多大？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PIRATE_FOX_NULL_NULL","text":{"KOREA":"수송 차량 십여 대 정도입니다!","JPN":"輸送車両が十数台程度です！","ENG":"A dozen transport vehicles.","TWN":"大概十多輛運輸車輛！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIRATE_FOX_NULL_NULL","text":{"KOREA":"그 주위를 퓨처 앳 워의 메카닉 다수가 호위하고 있습니다.","JPN":"その周辺をフューチャーアットウォーのメカニックが\\n取り囲んでいます。","ENG":"They're escorted by several Future-at-War mechs.","TWN":"天啟兵器的幾個裝甲部隊在周圍進行保護。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그거 좋은 소식이군. 내 수집품들이 이걸로 또 늘겠어.","JPN":"そりゃあグッドニュースだな。これでまた俺のコレクションが\\n増えそうだ。","ENG":"That's good to hear. They'll make a good addition to my collection.","TWN":"那可真是好消息，我又能添幾件收藏品了。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"자!","JPN":"さあ！","ENG":"Now!","TWN":"好！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};